final:
module current_sensor (
    input [3:0] obf_current_input,
    output reg [2:0] current_status
);

always @(*) begin
    if (obf_current_input < 4) 
        current_status = 3'b000; // Low
    else if (obf_current_input >= 4 && obf_current_input <= 11) 
        current_status = 3'b001; // Medium
    else 
        current_status = 3'b010; // High
end

endmodule
